import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import StarWarsAPI from '../services/StarWarsAPI'
import Card from 'react-bootstrap/Card'
import CardText from 'react-bootstrap/Card'
import CardBody from 'react-bootstrap/Card'
import Button from 'react-bootstrap/Button'
import Row from 'react-bootstrap/Row'
import Col from 'react-bootstrap/Col'


const Characters = () => {
	const [characters, setCharacters] = useState([])
	const [page, setPage] = useState(1)
	const [allData, setAllData] = useState([])

	const getCharacters = async () => {

		const data = await StarWarsAPI.getCharacters()

        setCharacters(data);
	}

	const getCharactersAllData = async () => {

		const data = await StarWarsAPI.getCharactersAllData()

        setAllData(data);
	}
	 	/**
        * Extract ID from SWAPI url
        */
		const getIdFromUrl = (url) => {
            // eslint-disable-next-line no-unused-vars
        const [_endpoint, id] = url
		         .replace('https://swapi.dev/api/people/?page=', '')
                .slice(0, -1)
                .split('/')
        return id
    }

	const handlePreviousPage = () => {

		// const previousPage = getIdFromUrl(allData.previous);
		// console.log("previous", previousPage)
		// if(previousPage) {
		// 	setPage(previousPage);
		// }
		// else {
		// 	return
		// }
	}

	const handleNextPage = () => {
		const url = allData.next;
		const url2 = url.replace('https://swapi.dev/api/people/?page=', '')
		const url3 = url2.slice(2, -1);
		const url4 = url3.split('/');
		console.log("url", url2)
		// const nextPage = getIdFromUrl(allData.next);
		// console.log("next", nextPage)
		// if(nextPage) {
		// 	setPage(nextPage);
		// }
		// else {
		// 	return
		// }
	}

	useEffect(() => {
		getCharacters()
		getCharactersAllData()
	}, [])

	return (
		<>
			<h1 className="films-heading">People</h1>

			{characters.length > 0 && (
				<>
				 <Row xs={1} md={2} lg={3} className="filmslist">
					{characters.map((character, index) =>
					<Col key={++index}>
						<Card className="film" style={{ width: '22rem' }}>
                            <CardBody>
                            <Card.Title className="film-title">{character.name}</Card.Title>

                            <CardText className="film-info">
                            <p className="film-id">Gender {character.gender}</p>
                            <p className="film-release">Born {character.birth_year}</p>
                            <p>In {character.films.length}</p>
                            </CardText>
							<Button variant="primary" as={Link} to={`/people/${++index}`} className="film-readmore">Read more</Button>
							</CardBody>
						</Card>
						</Col>
					)}
				</Row>
				<div className="button-container">
				<Button variant="primary" onClick={handlePreviousPage}  className="next-page">Previous page</Button>
				<p>Page <span>{page}</span><span>?</span></p>
				<Button variant="primary" onClick={handleNextPage}  className="next-page">Next page</Button>
				</div>
				</>
			)} 


			{characters.length === 0 && (
				<p className="status">No films!</p>
			)}

		</>
	)
}

export default Characters;
